def gen(rng, size):
    depth = max(1, size)
    def build(d):
        if d <= 0 or rng.random() < 0.3:
            return rng.choice(['t', 'f'])
        op = rng.choice(['!', '&', '|'])
        if op == '!':
            return '!(' + build(d - 1) + ')'
        k = rng.randrange(1, 4)
        return op + '(' + ','.join(build(d - 1) for _ in range(k)) + ')'
    return [build(depth)]

