class Solution:
    def parseBoolExpr(self, expression):
        def parse(i):
            c = expression[i]
            if c == 't':
                return True, i + 1
            if c == 'f':
                return False, i + 1
            op = c
            i += 2
            vals = []
            while expression[i] != ')':
                if expression[i] == ',':
                    i += 1
                    continue
                v, i = parse(i)
                vals.append(v)
            i += 1
            if op == '!':
                return (not vals[0]), i
            if op == '&':
                return all(vals), i
            return any(vals), i
        result, _ = parse(0)
        return result

