class Solution:
    def parseBoolExpr(self, expression):
        stack = []
        for ch in expression:
            if ch == ',':
                continue
            if ch == ')':
                vals = []
                while stack[-1] != '(':
                    vals.append(stack.pop())
                stack.pop()
                op = stack.pop()
                if op == '!':
                    stack.append(not vals[0])
                elif op == '&':
                    stack.append(all(vals))
                else:
                    stack.append(any(vals))
            elif ch == 't':
                stack.append(True)
            elif ch == 'f':
                stack.append(False)
            else:
                stack.append(ch)
        return stack[0]

