var parseBoolExpr = function(expression) {
    const stack = [];
    for (const ch of expression) {
        if (ch === ',') continue;
        if (ch === ')') {
            const vals = [];
            while (stack[stack.length - 1] !== '(') vals.push(stack.pop());
            stack.pop();
            const op = stack.pop();
            if (op === '!') stack.push(!vals[0]);
            else if (op === '&') stack.push(vals.every(v => v));
            else stack.push(vals.some(v => v));
        } else if (ch === 't') {
            stack.push(true);
        } else if (ch === 'f') {
            stack.push(false);
        } else {
            stack.push(ch);
        }
    }
    return stack[0];
};
